import { InputRule } from "./inputrules.js";
/// Converts double dashes to an emdash.
export const emDash = new InputRule(/--$/, "ŌĆö", { inCodeMark: false });
/// Converts three dots to an ellipsis character.
export const ellipsis = new InputRule(/\.\.\.$/, "ŌĆ”", { inCodeMark: false });
/// ŌĆ£SmartŌĆØ opening double quotes.
export const openDoubleQuote = new InputRule(/(?:^|[\s\{\[\(\<'"\u2018\u201C])(")$/, "ŌĆ£", { inCodeMark: false });
/// ŌĆ£SmartŌĆØ closing double quotes.
export const closeDoubleQuote = new InputRule(/"$/, "ŌĆØ", { inCodeMark: false });
/// ŌĆ£SmartŌĆØ opening single quotes.
export const openSingleQuote = new InputRule(/(?:^|[\s\{\[\(\<'"\u2018\u201C])(')$/, "ŌĆś", { inCodeMark: false });
/// ŌĆ£SmartŌĆØ closing single quotes.
export const closeSingleQuote = new InputRule(/'$/, "ŌĆÖ", { inCodeMark: false });
/// Smart-quote related input rules.
export const smartQuotes = [
    openDoubleQuote,
    closeDoubleQuote,
    openSingleQuote,
    closeSingleQuote,
];
